return [
  {
    json: {
      source_type: 'rss',
      source_name: 'OpenAI YouTube',
      title: 'Example source item',
      canonical_url: 'https://example.com/post',
      original_id: 'yt:abc123',
      author: 'OpenAI',
      published_at: '2026-04-17T09:00:00-04:00',
      raw_html: '<p>This is the original HTML body.</p>',
      raw_text: 'This is the original HTML body.',
      media_type: 'text',
      obsidian_inbox_dir: '00_Inbox/AI_Information_Processor',
      extra_tags: ['example-source'],
      upstream_task_id: '',
      upstream_view_token: '',
      upstream_summary: '',
      privacy_level: 'public',
      external_llm_allowed: true,
      original_item: {
        source: 'example'
      }
    }
  }
];

const rightRotate = (value, amount) => (value >>> amount) | (value << (32 - amount));

const sha256 = (value = '') => {
  const utf8 = unescape(encodeURIComponent(String(value)));
  const maxWord = 2 ** 32;
  const words = [];
  const asciiBitLength = utf8.length * 8;
  const hash = [];
  const k = [];
  const isComposite = {};

  for (let candidate = 2; k.length < 64; candidate += 1) {
    if (!isComposite[candidate]) {
      for (let multiple = candidate * candidate; multiple < 512; multiple += candidate) {
        isComposite[multiple] = true;
      }
      if (hash.length < 8) {
        hash.push((Math.sqrt(candidate) * maxWord) | 0);
      }
      k.push((candidate ** (1 / 3) * maxWord) | 0);
    }
  }

  let message = `${utf8}\x80`;
  while ((message.length % 64) !== 56) {
    message += '\x00';
  }

  for (let i = 0; i < message.length; i += 1) {
    words[i >> 2] |= message.charCodeAt(i) << ((3 - (i % 4)) * 8);
  }

  words.push((asciiBitLength / maxWord) | 0);
  words.push(asciiBitLength);

  for (let j = 0; j < words.length; j += 16) {
    const w = words.slice(j, j + 16);
    const workingHash = hash.slice();

    for (let i = 0; i < 64; i += 1) {
      const w15 = w[i - 15];
      const w2 = w[i - 2];
      const sigma0 = i < 16 ? 0 : (rightRotate(w15, 7) ^ rightRotate(w15, 18) ^ (w15 >>> 3));
      const sigma1 = i < 16 ? 0 : (rightRotate(w2, 17) ^ rightRotate(w2, 19) ^ (w2 >>> 10));
      w[i] = i < 16 ? w[i] : (((w[i - 16] + sigma0) | 0) + ((w[i - 7] + sigma1) | 0)) | 0;

      const [a, b, c, d, e, f, g, h] = workingHash;
      const sum1 = rightRotate(e, 6) ^ rightRotate(e, 11) ^ rightRotate(e, 25);
      const choice = (e & f) ^ (~e & g);
      const temp1 = (((((h + sum1) | 0) + choice) | 0) + k[i] + w[i]) | 0;
      const sum0 = rightRotate(a, 2) ^ rightRotate(a, 13) ^ rightRotate(a, 22);
      const majority = (a & b) ^ (a & c) ^ (b & c);
      const temp2 = (sum0 + majority) | 0;

      workingHash[0] = (temp1 + temp2) | 0;
      workingHash[1] = a;
      workingHash[2] = b;
      workingHash[3] = c;
      workingHash[4] = (d + temp1) | 0;
      workingHash[5] = e;
      workingHash[6] = f;
      workingHash[7] = g;
    }

    for (let i = 0; i < 8; i += 1) {
      hash[i] = (hash[i] + workingHash[i]) | 0;
    }
  }

  return hash.slice(0, 8).map((valuePart) => (valuePart >>> 0).toString(16).padStart(8, '0')).join('');
};

const slugify = (value = '') => String(value)
  .normalize('NFKD')
  .replace(/[\u0300-\u036f]/g, '')
  .replace(/[^a-zA-Z0-9\u4e00-\u9fa5]+/g, '-')
  .replace(/^-+|-+$/g, '')
  .toLowerCase();

const stripHtml = (value = '') => String(value)
  .replace(/<style[\s\S]*?<\/style>/gi, ' ')
  .replace(/<script[\s\S]*?<\/script>/gi, ' ')
  .replace(/<[^>]+>/g, ' ')
  .replace(/&nbsp;/gi, ' ')
  .replace(/&amp;/gi, '&')
  .replace(/\s+/g, ' ')
  .trim();

const normalizeMultiline = (value = '') => String(value || '')
  .replace(/\r\n/g, '\n')
  .replace(/\u0000/g, '')
  .replace(/[ \t]+\n/g, '\n')
  .replace(/\n{3,}/g, '\n\n')
  .trim();

const normalizeSingleLine = (value = '') => normalizeMultiline(value)
  .replace(/\s+/g, ' ')
  .trim();

const stableHash = (value) => sha256(String(value));
const normalizePrivacyLevel = (value) => {
  const normalized = String(value || 'public').trim().toLowerCase();
  if (['public', 'semi_private', 'private', 'sensitive'].includes(normalized)) {
    return normalized;
  }
  return 'public';
};

const normalizeTimestamp = (value = '') => {
  const normalized = String(value || '').trim();
  if (!normalized) {
    return '';
  }

  const match = normalized.match(/^(\d{1,2}):(\d{2}):(\d{2})(?:\.(\d{1,3}))?$/);
  if (!match) {
    return '';
  }

  return `${match[1].padStart(2, '0')}:${match[2]}:${match[3]}${match[4] ? `.${match[4].padEnd(3, '0')}` : ''}`;
};

const buildTopicHint = (value = '') => {
  const normalized = normalizeMultiline(value).replace(/\n+/g, ' ');
  if (!normalized) {
    return '';
  }

  const firstClause = normalized.match(/^.{1,24}?(?=[。！？!?；;，,:]|$)/)?.[0] || normalized.slice(0, 24);
  return firstClause.trim();
};

const formatChunkForContentText = (chunk) => {
  const speaker = normalizeSingleLine(chunk.speaker || '');
  return speaker ? `${speaker}：${chunk.text}` : chunk.text;
};

const normalizeChunks = (value) => {
  if (!Array.isArray(value)) {
    return [];
  }

  const prepared = [];
  for (const chunk of value) {
    if (!chunk || typeof chunk !== 'object') {
      continue;
    }

    const text = normalizeMultiline(chunk.text || chunk.content || '');
    if (!text) {
      continue;
    }

    const chunkId = normalizeSingleLine(chunk.chunk_id || chunk.chunkId || '');
    const startTime = normalizeTimestamp(chunk.start_time || chunk.startTime || '');
    const endTime = normalizeTimestamp(chunk.end_time || chunk.endTime || '');
    const speaker = normalizeSingleLine(chunk.speaker || chunk.speaker_name || '');
    const topicHint = normalizeSingleLine(chunk.topic_hint || chunk.topicHint || buildTopicHint(text));

    prepared.push({
      chunk_id: chunkId,
      start_time: startTime,
      end_time: endTime,
      speaker,
      text,
      topic_hint: topicHint
    });
  }

  if (!prepared.length) {
    return [];
  }

  const hasTimedChunk = prepared.some((chunk) => chunk.start_time || chunk.end_time);
  const normalized = [];
  let cursor = 0;

  for (const chunk of prepared) {
    const contentSegment = formatChunkForContentText(chunk);
    const charStart = cursor;
    const charEnd = charStart + contentSegment.length;

    normalized.push({
      chunk_id: chunk.chunk_id || `${hasTimedChunk ? 't' : 'c'}${String(normalized.length + 1).padStart(hasTimedChunk ? 4 : 3, '0')}`,
      ...(chunk.start_time ? { start_time: chunk.start_time } : {}),
      ...(chunk.end_time ? { end_time: chunk.end_time } : {}),
      ...(chunk.speaker ? { speaker: chunk.speaker } : {}),
      text: chunk.text,
      char_start: charStart,
      char_end: charEnd,
      ...(chunk.topic_hint ? { topic_hint: chunk.topic_hint } : {})
    });

    cursor = charEnd + 2;
  }

  return normalized;
};

const title = normalizeSingleLine($json.title || '') || 'untitled';
const canonicalUrl = String($json.canonical_url || '').trim();
const publishedAtRaw = $json.published_at || new Date().toISOString();
const publishedAt = new Date(publishedAtRaw).toISOString();
const ingestedAt = $json.ingested_at ? new Date($json.ingested_at).toISOString() : new Date().toISOString();
const rawHtml = String($json.raw_html || $json.content_html || '').trim();
const rawText = normalizeMultiline($json.raw_text || '');
const normalizedChunks = normalizeChunks($json.chunks);
const contentText = normalizedChunks.length
  ? normalizedChunks.map((chunk) => formatChunkForContentText(chunk)).join('\n\n').trim()
  : normalizeMultiline(rawText || stripHtml(rawHtml));
const author = normalizeSingleLine($json.author || '');
const sourceType = normalizeSingleLine($json.source_type || 'manual') || 'manual';
const sourceName = normalizeSingleLine($json.source_name || '');
const originalId = normalizeSingleLine($json.original_id || '');
const mediaType = normalizeSingleLine($json.media_type || 'text') || 'text';
const obsidianInboxDir = String($json.obsidian_inbox_dir || $json.obsidianInboxDir || '00_Inbox/AI_Information_Processor').trim() || '00_Inbox/AI_Information_Processor';
const upstreamTaskId = normalizeSingleLine($json.upstream_task_id || '');
const upstreamViewToken = normalizeSingleLine($json.upstream_view_token || '');
const upstreamSummary = normalizeMultiline($json.upstream_summary || '');
const privacyLevel = normalizePrivacyLevel($json.privacy_level || $json.privacyLevel || 'public');
const externalLlmAllowedInput = $json.external_llm_allowed ?? $json.externalLlmAllowed;
const externalLlmAllowed = externalLlmAllowedInput === undefined
  ? !['private', 'sensitive'].includes(privacyLevel)
  : Boolean(externalLlmAllowedInput);
const originalItem = $json.original_item ?? null;
const existingTags = Array.isArray($json.tags) ? $json.tags : [];
const extraTags = Array.isArray($json.extra_tags) ? $json.extra_tags : [];

let sourceHost = normalizeSingleLine($json.source_host || '');
if (!sourceHost) {
  const hostMatch = canonicalUrl.match(/^https?:\/\/([^\/?#]+)/i);
  if (hostMatch?.[1]) {
    sourceHost = hostMatch[1].replace(/^www\./i, '');
  }
}
if (!sourceHost) {
  sourceHost = 'unknown-source';
}

const itemKey = canonicalUrl
  || (sourceType && originalId ? `${sourceType}:${originalId}` : '')
  || [title, publishedAt, author].filter(Boolean).join('::');
const itemId = stableHash(itemKey);
const contentHash = `sha256:${stableHash(contentText)}`;
const tags = [...new Set([
  'inbox',
  'ai-information-processor',
  ...existingTags.map((tag) => normalizeSingleLine(tag)),
  ...extraTags.map((tag) => normalizeSingleLine(tag)),
  slugify(sourceHost),
  slugify(sourceName),
  slugify(sourceType)
].filter(Boolean))];

return {
  json: {
    item_id: itemId,
    source_type: sourceType,
    source_name: sourceName || sourceHost || 'unknown-source',
    source_host: sourceHost,
    original_id: originalId,
    canonical_url: canonicalUrl,
    title,
    author,
    published_at: publishedAt,
    ingested_at: ingestedAt,
    media_type: mediaType,
    content_text: contentText,
    ...(normalizedChunks.length ? { chunks: normalizedChunks } : {}),
    content_html: rawHtml,
    upstream_task_id: upstreamTaskId,
    upstream_view_token: upstreamViewToken,
    upstream_summary: upstreamSummary,
    privacy_level: privacyLevel,
    external_llm_allowed: externalLlmAllowed,
    content_hash: contentHash,
    tags,
    obsidianInboxDir,
    original_item: originalItem
  }
};
